    total = tag_read_size(fit);
    if (total >= need + MIN_BLK) {
        slot_take_split(a, fit, req, need);
    } else {
        slot_take_whole(a, fit, total);
    }
    idx = a->slot_count++;
    if (idx >= MAX_SLOTS) {
        return -1;
