}

int emit_matrix(const CaseResult *cases, int count, const char *audit_path) {
    FILE *fp = fopen(audit_path, "w");
    int i;
    if (!fp) {
        return -1;
    }
    fprintf(fp, "{\n  \"cases\": [\n");
    for (i = 0; i < count; i++) {
        write_case(fp, &cases[i], i + 1 == count);
    }
    fprintf(fp, "  ]\n}\n");
    fclose(fp);
    return 0;
}
