void xa0(Block *a, size_t b) {
    size_t *hdr = (size_t *)(void *)(a->base + a->off);
    size_t *ftr;
    hdr[0] = b;
    hdr[1] = 0;
    ftr = (size_t *)(void *)(a->base + a->off + (b / 2));
